entry.content:
1.Record避免繁琐的DTO语法、JAVA16+支持、用于少业务逻辑、单纯做数据存储。数据比对时可以重写equal,选择要比对的值，默认全属性比对，再重写hashcode，避免报错
Student实体import java.time.LocalDate;    // record 自动生成构造器、equals、hashCode、toString  public record Student (          String id, //学号          String name,// 姓名          int age,// 年龄          String grade,// 年级          LocalDate enrollDate // 入学时间  )&#123;          // 可以添加自定义方法          public boolean isAdult() &#123;              return age &gt;= 18;          &#125;          //紧凑构造器，用于验证          public Student &#123;              if(id==null || id.isBlank())&#123;                  throw new IllegalArgumentException(&quot;学号不能为空&quot;);              &#125;              if(name==null || name.isBlank())&#123;                  throw new IllegalArgumentException(&quot;姓名不能为空&quot;);              &#125;              if(age&lt;0)&#123;                  throw new IllegalArgumentException(&quot;年龄不能小于0&quot;);              &#125;              if(age&gt;150)&#123;                  throw new IllegalArgumentException(&quot;年龄不能大于150&quot;);              &#125;          &#125;      &#125;
学生Serviceimport java.util.*;  import java.util.stream.Collectors;    public class StudentService &#123;      private final List&lt;Student&gt; students = new ArrayList&lt;&gt;();        //添加学生      public boolean addStudent(Student student) &#123;          boolean exists = students.stream().anyMatch(s -&gt; s.id().equals(student.id()));          if (exists) &#123;              System.out.println(&quot;该学生已存在，学号为：&quot; + student.id());              return false;          &#125;            students.add(student);          System.out.println(&quot;添加成功&quot; + student.name());          return true;      &#125;        //删除学生      public boolean deleteStudent(String id) &#123;          boolean removed = students.removeIf(s -&gt; s.id().equals(id));          if (removed) &#123;              System.out.println(&quot;删除成功，学号为：&quot; + id);          &#125; else &#123;              System.out.println(&quot;该学生不存在，学号为：&quot; + id);          &#125;          return removed;      &#125;        //更新学生信息      public boolean updateStudent(String id, String newName, Integer newAge) &#123;          for (int i = 0; i &lt; students.size(); i++) &#123;              Student s = students.get(i);              if (s.id().equals(id)) &#123;                  Student updated = new Student(                          s.id(),                          newName != null ? newName : s.name(),                          newAge != null ? newAge : s.age(),                          s.grade(),                          s.enrollDate()                  );                  students.set(i, updated);                  System.out.println(&quot;更新成功，学号为：&quot; + id);                  return true;              &#125;          &#125;          System.out.println(&quot;该学生不存在，学号为：&quot; + id);          return false;      &#125;        //查询学生按学号      public Optional&lt;Student&gt; findById(String id) &#123;          return students.stream()                  .filter(s -&gt; s.id().equals(id))                  .findFirst();      &#125;        //查询学生按姓名      public List&lt;Student&gt; findByName(String name) &#123;          return students.stream()                  .filter(s -&gt; s.name().equalsIgnoreCase(name))                  .toList();      &#125;        //查询学生按年级      public List&lt;Student&gt; findByGrade(String grade) &#123;          return students.stream()                  .filter(s -&gt; s.grade().equals(grade))                  .toList();      &#125;        //查询所有学生      public List&lt;Student&gt; findAll() &#123;          return new ArrayList&lt;&gt;(students);//返回副本，保护内部数据      &#125;        //查询所有学生按年龄排序      public List&lt;Student&gt; sortByAge() &#123;          return students.stream()                  .sorted(Comparator.comparing(Student::age))                  .toList();      &#125;      // 统计成年学生      public long countAdults() &#123;          return students.stream()                  .filter(Student::isAdult)                  .count();      &#125;        // 获取所有年级      public Set&lt;String&gt; getAllGrades() &#123;          return students.stream()                  .map(Student::grade)                  .collect(Collectors.toSet());      &#125;  &#125;
主程序import java.time.LocalDate;  import java.util.List;    public class Main &#123;      public static void main(String[] args) &#123;          StudentService service = new StudentService();            System.out.println(&quot;=== 学生管理系统 ===\n&quot;);            // 1. 添加学生          System.out.println(&quot;--- 添加学生 ---&quot;);          Student s1 = new Student(&quot;001&quot;, &quot;张三&quot;, 18, &quot;大一&quot;, LocalDate.of(2024, 9, 1));          System.out.println(&quot;添加成功: &quot; + s1);          Student s2 = new Student(&quot;002&quot;, &quot;李四&quot;, 20, &quot;大二&quot;, LocalDate.of(2023, 9, 1));          Student s3 = new Student(&quot;003&quot;, &quot;王五&quot;, 17, &quot;大一&quot;, LocalDate.of(2024, 9, 1));          Student s4 = new Student(&quot;004&quot;, &quot;赵六&quot;, 22, &quot;大三&quot;, LocalDate.of(2022, 9, 1));            service.addStudent(s1);          service.addStudent(s2);          service.addStudent(s3);          service.addStudent(s4);            // 测试重复学号          service.addStudent(new Student(&quot;001&quot;, &quot;重复&quot;, 20, &quot;大四&quot;, LocalDate.now()));            System.out.println();            // 2. 查询所有学生          System.out.println(&quot;--- 所有学生 ---&quot;);          service.findAll().forEach(System.out::println);            System.out.println();            // 3. 按学号查询          System.out.println(&quot;--- 按学号查询 ---&quot;);          service.findById(&quot;002&quot;).ifPresentOrElse(                  s -&gt; System.out.println(&quot;找到: &quot; + s),                  () -&gt; System.out.println(&quot;未找到&quot;)          );            System.out.println();            // 4. 按姓名查询          System.out.println(&quot;--- 按姓名查询 ---&quot;);          List&lt;Student&gt; result = service.findByName(&quot;张三&quot;);          result.forEach(System.out::println);            System.out.println();            // 5. 按年级查询          System.out.println(&quot;--- 按年级查询 ---&quot;);          service.findByGrade(&quot;大一&quot;).forEach(System.out::println);            System.out.println();            // 6. 更新学生          System.out.println(&quot;--- 更新学生 ---&quot;);          service.updateStudent(&quot;003&quot;, &quot;王五改&quot;, 18);          System.out.println(&quot;更新后: &quot; + service.findById(&quot;003&quot;).get());            System.out.println();            // 7. 删除学生          System.out.println(&quot;--- 删除学生 ---&quot;);          service.deleteStudent(&quot;004&quot;);            System.out.println();            // 8. 按年龄排序          System.out.println(&quot;--- 按年龄排序 ---&quot;);          service.sortByAge().forEach(System.out::println);            System.out.println();            // 9. 统计数据          System.out.println(&quot;--- 统计信息 ---&quot;);          System.out.println(&quot;成年学生数: &quot; + service.countAdults());          System.out.println(&quot;所有年级: &quot; + service.getAllGrades());            System.out.println();            // 10. 最终学生列表          System.out.println(&quot;--- 最终学生列表 ---&quot;);          service.findAll().forEach(System.out::println);      &#125;  &#125;

简介一个持久层框架 负责数据库数据数据操作简化JDBC的操作：硬编码 、操作繁琐 通过配置连接信息和SQL语句的XML文件和封装功能代码直接获取结果
快速入门MyBatis中文网

创建模块 
编写mybatis-config.xml (数据库表、用户、密码)

&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot; ?&gt;  &lt;!DOCTYPE configuration          PUBLIC &quot;-//mybatis.org//DTD Config 3.0//EN&quot;          &quot;http://mybatis.org/dtd/mybatis-3-config.dtd&quot;&gt;  &lt;configuration&gt;  &lt;!-- environments 配置数据库连接环境信息，可配置多个environment，通过default属性切换不同的environment--&gt;    &lt;environments default=&quot;development&quot;&gt;          &lt;environment id=&quot;development&quot;&gt;              &lt;transactionManager type=&quot;JDBC&quot;/&gt;              &lt;dataSource type=&quot;POOLED&quot;&gt;                  &lt;property name=&quot;driver&quot; value=&quot;com.mysql.cj.jdbc.Driver&quot;/&gt;                  &lt;property name=&quot;url&quot; value=&quot;jdbc:mysql:///数据库名?useSSL=false&quot;/&gt;                  &lt;property name=&quot;username&quot; value=&quot;用户名&quot;/&gt;                  &lt;property name=&quot;password&quot; value=&quot;密码&quot;/&gt;              &lt;/dataSource&gt;             &lt;/environment&gt;        &lt;/environments&gt;        &lt;mappers&gt;        		&lt;mapper resource=&quot;UserMapper.xml&quot;/&gt;  &lt;!-- resource目录下文件--&gt;    &lt;/mappers&gt;&lt;/configuration&gt;

编写sql映射文件 mapper.xml

&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot; ?&gt;  &lt;!DOCTYPE mapper          PUBLIC &quot;-//mybatis.org//DTD Mapper 3.0//EN&quot;          &quot;http://mybatis.org/dtd/mybatis-3-mapper.dtd&quot;&gt;  &lt;!-- namespace:名称空间--&gt;  &lt;mapper namespace=&quot;test&quot;&gt;  &lt;!--可指向pojo包--&gt;    &lt;select id=&quot;selectAll&quot; resultType=&quot;com.study.mybatis1.pojo.User&quot;&gt;          select * from tb_user  &lt;!-- tb_user 报错 在idea连接数据库--&gt;    &lt;/select&gt;  &lt;/mapper&gt;

1.创建pojo类2.加载mybatis-config.xml连接配置3.获取SqlSession对象，执行Sql语句4.释放资源

Mapper代理开发未使用代理开发 ：List&lt;User&gt; user = sqlSession.selectList(&quot;test.selectAll&quot;);
“test.selectAll”会随着mapper的增加而混乱，且需要自己填写到代码里属于硬编码，不便管理
使用代理开发 ：UserMapper userMapper = sqlSession.getMapper(UserMapper.class);  List&lt;User&gt; users = userMapper.selectAll();
在resource目录下创建目录com&#x2F;study&#x2F;mybatis&#x2F;mapper和源文件mapper目录一直，再把mapper.xml文件放到该目录下。源文件mapper下写接口和对应方法。
包扫描的方式简化SQL映射文件的加载&lt;mappers&gt;      &lt;!--mapper resource=&quot;com/study/mybatis1/mapper/UserMapper.xml&quot;/--&gt;      &lt;!-- Mapper代理方式--&gt;      &lt;package name=&quot;com.study.mybatis1.mapper&quot;/&gt;  &lt;/mappers&gt;
Mybatis核心配置文件&lt;typeAliases&gt;      &lt;package name=&quot;com.study.mybatis1.pojo&quot;/&gt;  &lt;/typeAliases&gt;
resultType省略前面包名
&lt;mapper namespace=&quot;com.study.mybatis1.mapper.UserMapper&quot;&gt;      &lt;select id=&quot;selectAll&quot; resultType=&quot;User&quot;&gt;          select * from tb_user      &lt;/select&gt;  &lt;/mapper&gt;
配置标签要遵守顺序
